void abc (char *x1, char *y1)
{
  char x;
  x=*y1;
  printf("%c%c%c\n",x,*x1,*y1);
  {
    char x=’T’;
    x++;
    (*x1)++;
    printf("%c%c%c\n",x,*x1,*y1);
  }
  printf("%c%c%c\n",x,*x1,*y1);
}
void main()
{
  abc(&x,&y);
  printf("%c%c\n",x,y);
}
