public class Posoda {
private double vol;
private double zas;
public Posoda(double v) {
this.vol = v;
zas = 0;
}
public Posoda(Posoda p) {
this.vol = p.vol;
this.zas = p.zas;
}
public String toString() {
return new String("Zasedeno je "+zas+"L od "+vol+"L");
}
public void dotoci(double n) {
zas += n;
if (zas>vol)
zas = vol;
}
public void iztoci(double n) {
zas -= n;
if (zas<0)
zas = 0;
}
}
