v.izpis();  // izpiše 00:00

tasks.solution:
class Ura {
public int ura;
public int minute;
public Ura() {
this.ura = 0;
this.minute = 0;
}
public Ura(int ura, int minute) {
this.ura = 0;
this.minute = 0;
if (ura >= 0 && ura <= 23)
this.ura = ura;
if (minute >= 0 && minute <= 59)
this.minute = minute;
}
public void povecaj() {
minute = (minute + 1) % 60;
if (minute == 0)
ura = (ura + 1) % 24;
}
public void izpis() {
if (ura < 10)
System.out.print("0"+ura+":");
else
System.out.print(ura+":");
if (minute < 10)
System.out.print("0"+minute);
else
System.out.print(minute);
System.out.println();
}
}
